using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace WeatherMcpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// Non-static class — HttpClient and ILogger are constructor-injected via DI.
/// </summary>
[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather for a location given its latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6062 for Seattle)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3321 for Seattle)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching current weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

        var response = await httpClient.GetStringAsync(url, cancellationToken);

        // Re-serialize to pretty-print for the LLM
        using var doc = JsonDocument.Parse(response);
        return JsonSerializer.Serialize(doc.RootElement, JsonOptions);
    }

    [McpServerTool, Description("Get a 7-day daily weather forecast for a location.")]
    public async Task<string> GetWeatherForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching 7-day forecast for ({Lat}, {Lon})", latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min,precipitation_sum"
                + $"&forecast_days=7";

        var response = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(response);
        return JsonSerializer.Serialize(doc.RootElement, JsonOptions);
    }
}

